class Solution:
    def minMovesToMakePalindrome(self, s: str) -> int:
        s = list(s)
        n = len(s)
        moves = 0
        for i in range(n // 2):
            if s[i] == s[n - i - 1]:
                continue
            for j in range(i + 1, n - i - 1):
                if s[j] == s[n - i - 1]:
                    s[i], s[j] = s[j], s[i]
                    moves += 1
                    break
        return moves

